{"path": "tmp/eval36_merger.py", "new_text": "import json

def merge_configs(*configs):
    result = {}
    for config in configs:
        for key, value in config.items():
            if isinstance(value, dict):
                if key in result:
                    result[key] = merge_configs(result[key], value)
                else:
                    result[key] = merge_configs({}, value)
            elif isinstance(value, list):
                if key in result:
                    result[key] = result[key] + value
                else:
                    result[key] = value
            else:
                result[key] = value
    return result


def validate_merge(*configs):
    conflicts = []
    for config in configs:\        for key, value in config.items():            if key in result:\                if type(value) != type(result[key]):                    conflicts.append(f"Type conflict for key '{key}': {type(value)} vs {type(result[key])}")            else:\                result[key] = value
    return conflicts"}

